#!/usr/bin/env python3
"""Synthetic pathway activity inputs for Ena/VASP proteins and T cell actin remodeling."""

from io import StringIO

import pandas as pd


CSV_TEXT = """gene,weight,signal
Ena/VASP proteins,1.0,2.5
Ena/VASP proteins_partner,0.7,1.8
Ena/VASP proteins_regulator,0.5,1.2"""


def load_pathway_activity_inputs() -> pd.DataFrame:
    return pd.read_csv(StringIO(CSV_TEXT))

